/**
 * YourStockForecast — app.js
 * ==========================
 * Handles: instant search, live ticker tape, table sorting,
 * pagination, number formatting, and page-specific init.
 */

// ── Instant symbol search ─────────────────────────────────────────────────────
(function initSearch() {
  const input    = document.getElementById('search-input');
  const resultsEl= document.getElementById('search-results');
  if (!input || !resultsEl) return;

  let index = [];
  let debounceTimer;

  // Load search index (generated by generate_hugo_data.py)
  fetch('/data/search_index.json')
    .then(r => r.json())
    .then(data => { index = data; })
    .catch(() => {});

  function showResults(query) {
    if (!query || query.length < 1) { hide(); return; }
    const q = query.toUpperCase();
    const matches = index
      .filter(item => item.s.startsWith(q) || item.s.includes(q))
      .slice(0, 10);

    if (!matches.length) { hide(); return; }

    resultsEl.innerHTML = matches.map(item => `
      <div class="search-item" onclick="location.href='/stocks/${item.s.toLowerCase().replace(/\./g,'-')}'">
        <span class="sym">${item.s}</span>
        <span class="name">${item.sec || ''}</span>
      </div>`).join('');
    resultsEl.classList.remove('hidden');
  }

  function hide() { resultsEl.classList.add('hidden'); }

  input.addEventListener('input', e => {
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => showResults(e.target.value.trim()), 120);
  });

  input.addEventListener('keydown', e => {
    if (e.key === 'Escape') { hide(); input.blur(); }
    if (e.key === 'Enter' && input.value.trim()) {
      const sym = input.value.trim().toUpperCase();
      location.href = `/stocks/${sym.toLowerCase().replace(/\./g, '-')}`;
    }
  });

  document.addEventListener('click', e => {
    if (!e.target.closest('.search-wrap')) hide();
  });
})();

// ── Sortable tables ───────────────────────────────────────────────────────────
// Attach after YSF.renderTable() populates a container.
// Usage: makeSortable(document.querySelector('.data-table'))
function makeSortable(table) {
  if (!table) return;
  const headers = table.querySelectorAll('th');
  let lastCol = -1, asc = true;

  headers.forEach((th, col) => {
    th.style.cursor = 'pointer';
    th.addEventListener('click', () => {
      asc = (col === lastCol) ? !asc : true;
      lastCol = col;
      const rows = Array.from(table.querySelectorAll('tbody tr'));
      rows.sort((a, b) => {
        const av = a.cells[col]?.textContent.replace(/[$,%x]/g,'').trim() || '';
        const bv = b.cells[col]?.textContent.replace(/[$,%x]/g,'').trim() || '';
        const an = parseFloat(av), bn = parseFloat(bv);
        const cmp = isNaN(an) || isNaN(bn) ? av.localeCompare(bv) : an - bn;
        return asc ? cmp : -cmp;
      });
      const tbody = table.querySelector('tbody');
      rows.forEach(r => tbody.appendChild(r));
      // Update header indicators
      headers.forEach((h, i) => {
        h.textContent = h.textContent.replace(/ [▲▼]$/, '');
        if (i === col) h.textContent += asc ? ' ▲' : ' ▼';
      });
    });
  });
}

// Observe any container that gets a .data-table injected and auto-sort it
const sortObserver = new MutationObserver(mutations => {
  mutations.forEach(m => m.addedNodes.forEach(node => {
    if (node.nodeType === 1) {
      const table = node.classList?.contains('data-table') ? node
                  : node.querySelector?.('.data-table');
      if (table) makeSortable(table);
    }
  }));
});
document.querySelectorAll('.table-wrap,[id$="-table"]').forEach(el =>
  sortObserver.observe(el, { childList: true, subtree: true })
);

// ── Pagination helper ─────────────────────────────────────────────────────────
class Paginator {
  constructor({ containerId, fetchFn, columns, pageSize = 50 }) {
    this.container = document.getElementById(containerId);
    this.fetchFn   = fetchFn;
    this.columns   = columns;
    this.pageSize  = pageSize;
    this.page      = 0;
    this.total     = null;
    this._render   = this._render.bind(this);
  }

  async load(page = 0) {
    this.page = page;
    YSF.setLoading(this.container?.id, true);
    try {
      const { data, total } = await this.fetchFn(page, this.pageSize);
      this.total = total;
      this._render(data);
    } catch (err) {
      if (this.container) YSF.showError(this.container.id, err.message);
    }
    YSF.setLoading(this.container?.id, false);
  }

  _render(data) {
    if (!this.container) return;
    YSF.renderTable(this.container.id, data, this.columns);
    // Append pagination controls
    if (this.total && this.total > this.pageSize) {
      const pages = Math.ceil(this.total / this.pageSize);
      const ctrl  = document.createElement('div');
      ctrl.className = 'pagination';
      ctrl.style.cssText = 'display:flex;gap:.5rem;justify-content:center;padding:1rem 0;font-size:.85rem';
      if (this.page > 0)
        ctrl.innerHTML += `<button class="btn btn-ghost btn-sm" onclick="this.closest('[data-pager]').__pager.load(${this.page-1})">← Prev</button>`;
      ctrl.innerHTML += `<span style="color:var(--text3);line-height:2">Page ${this.page+1} of ${pages} (${this.total} results)</span>`;
      if (this.page < pages - 1)
        ctrl.innerHTML += `<button class="btn btn-ghost btn-sm" onclick="this.closest('[data-pager]').__pager.load(${this.page+1})">Next →</button>`;
      this.container.appendChild(ctrl);
      this.container.setAttribute('data-pager', '1');
      this.container.__pager = this;
    }
  }
}

// ── Number / formatting utilities ─────────────────────────────────────────────
const fmt = {
  compact: v => {
    const n = parseFloat(v);
    if (isNaN(n)) return '—';
    if (Math.abs(n) >= 1e12) return (n/1e12).toFixed(2) + 'T';
    if (Math.abs(n) >= 1e9)  return (n/1e9).toFixed(2)  + 'B';
    if (Math.abs(n) >= 1e6)  return (n/1e6).toFixed(2)  + 'M';
    if (Math.abs(n) >= 1e3)  return (n/1e3).toFixed(1)  + 'K';
    return n.toFixed(2);
  }
};

// ── Toast notifications ───────────────────────────────────────────────────────
function toast(msg, type = 'info', duration = 3500) {
  const el = document.createElement('div');
  const bg = type === 'error' ? 'var(--neg)' : type === 'success' ? 'var(--pos)' : 'var(--accent)';
  el.style.cssText = `
    position:fixed;bottom:1.5rem;right:1.5rem;z-index:9999;
    background:${bg};color:#000;border-radius:8px;
    padding:.75rem 1.25rem;font-weight:600;font-size:.875rem;
    box-shadow:0 4px 20px rgba(0,0,0,.5);
    animation:slideIn .2s ease;pointer-events:none;`;
  el.textContent = msg;
  document.body.appendChild(el);
  setTimeout(() => el.remove(), duration);
}
const style = document.createElement('style');
style.textContent = `@keyframes slideIn{from{transform:translateY(20px);opacity:0}to{transform:none;opacity:1}}`;
document.head.appendChild(style);

// ── Live price refresh badge ───────────────────────────────────────────────────
// Pulses a small dot in the nav when data is refreshing
function showRefreshPulse() {
  let dot = document.getElementById('refresh-dot');
  if (!dot) {
    dot = document.createElement('span');
    dot.id = 'refresh-dot';
    dot.style.cssText = 'width:7px;height:7px;border-radius:50%;background:var(--accent);display:inline-block;margin-left:.5rem;animation:pulse 1s infinite';
    const brand = document.querySelector('.nav-brand');
    if (brand) brand.appendChild(dot);
    const ps = document.createElement('style');
    ps.textContent = `@keyframes pulse{0%,100%{opacity:1}50%{opacity:.3}}`;
    document.head.appendChild(ps);
  }
  dot.style.display = 'inline-block';
  setTimeout(() => { if (dot) dot.style.display = 'none'; }, 2500);
}

// Expose for use from page scripts
window.makeSortable = makeSortable;
window.Paginator    = Paginator;
window.fmt          = fmt;
window.toast        = toast;
window.showRefreshPulse = showRefreshPulse;
